module RefModule(
	input clk,
	input reset_n,
	input enable,
	input [7:0] data_in,
	output reg [7:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (!reset_n)
			q <= 8'b0;
		else if (enable)
			q <= data_in;
	end

endmodule
